using UniversityCatalog.Models;

namespace UniversityCatalog.Services;

public interface ICatalogService
{
    List<Department> GetDepartments();
    Department? GetDepartment(int id);
    List<Course> GetCourses(string? searchTerm = null, int? departmentId = null, int? credits = null);
    Course? GetCourse(int id);
    List<Course> GetFeaturedCourses();
    Instructor? GetInstructor(int id);
    bool SubmitEnrollment(EnrollmentRequest request);
}

using UniversityCatalog.Models;

namespace UniversityCatalog.Services;

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics, statistics, and data analysis." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Literature, writing, rhetoric, and communication studies." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Fundamental principles of matter, energy, and the universe." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Human civilization, cultures, and historical analysis." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Ada Lovelace", Title = "Professor of Computer Science", Bio = "Pioneering researcher in algorithms and programming languages with over 20 years of teaching experience. Published extensively in ACM and IEEE journals.", Email = "lovelace@university.edu", Office = "CS Building, Room 301" },
            new() { Id = 2, Name = "Dr. Alan Turing", Title = "Associate Professor of Computer Science", Bio = "Specialist in computational theory and artificial intelligence. Leads the university's Machine Learning Research Lab.", Email = "turing@university.edu", Office = "CS Building, Room 215" },
            new() { Id = 3, Name = "Dr. Emmy Noether", Title = "Professor of Mathematics", Bio = "Expert in abstract algebra and theoretical physics. Recipient of the Distinguished Teaching Award three years running.", Email = "noether@university.edu", Office = "Math Hall, Room 410" },
            new() { Id = 4, Name = "Dr. Carl Sagan", Title = "Professor of Physics", Bio = "Astrophysicist and science communicator. Research focuses on planetary science and the search for extraterrestrial intelligence.", Email = "sagan@university.edu", Office = "Physics Lab, Room 102" },
            new() { Id = 5, Name = "Dr. Maya Angelou", Title = "Professor of English", Bio = "Award-winning author and poet. Specializes in American literature, creative writing, and cultural criticism.", Email = "angelou@university.edu", Office = "Humanities Building, Room 508" },
            new() { Id = 6, Name = "Dr. Howard Zinn", Title = "Associate Professor of History", Bio = "Historian and social activist. Research focuses on labor history, civil rights movements, and historiography.", Email = "zinn@university.edu", Office = "Humanities Building, Room 312" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, data structures, and basic object-oriented programming. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, DepartmentName = "Computer Science", InstructorId = 1, IsFeatured = true },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques (sorting, searching, dynamic programming). Prerequisite: CS 101.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", DepartmentId = 1, DepartmentName = "Computer Science", InstructorId = 2, IsFeatured = true },
            new() { Id = 3, Code = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, indexing, transaction processing, and an introduction to NoSQL databases. Includes a semester-long group project.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", DepartmentId = 1, DepartmentName = "Computer Science", InstructorId = 1 },
            new() { Id = 4, Code = "CS 450", Title = "Machine Learning", Description = "Supervised and unsupervised learning, neural networks, decision trees, and model evaluation. Requires strong foundations in linear algebra and statistics.", Credits = 4, Schedule = "Tue/Thu 1:00–2:30 PM", DepartmentId = 1, DepartmentName = "Computer Science", InstructorId = 2, IsFeatured = true },
            new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, integrals, and the Fundamental Theorem of Calculus. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, DepartmentName = "Mathematics", InstructorId = 3 },
            new() { Id = 6, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations. Essential for computer science, physics, and engineering students.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", DepartmentId = 2, DepartmentName = "Mathematics", InstructorId = 3, IsFeatured = true },
            new() { Id = 7, Code = "MATH 301", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis. Applications to data science and research.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 2, DepartmentName = "Mathematics", InstructorId = 3 },
            new() { Id = 8, Code = "ENG 101", Title = "College Composition", Description = "Develop critical reading, analytical thinking, and academic writing skills. Emphasis on thesis-driven essays, research methods, and proper citation.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 3, DepartmentName = "English", InstructorId = 5 },
            new() { Id = 9, Code = "ENG 220", Title = "American Literature", Description = "Survey of American literary works from the colonial era to the present. Explores themes of identity, democracy, and social change through major authors.", Credits = 3, Schedule = "Tue/Thu 2:00–3:15 PM", DepartmentId = 3, DepartmentName = "English", InstructorId = 5, IsFeatured = true },
            new() { Id = 10, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with weekly lab sessions. Co-requisite: MATH 101.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM + Thu Lab 3:00–5:00 PM", DepartmentId = 4, DepartmentName = "Physics", InstructorId = 4 },
            new() { Id = 11, Code = "PHYS 201", Title = "General Physics II", Description = "Electricity, magnetism, optics, and modern physics. Continuation of PHYS 101 with lab component.", Credits = 4, Schedule = "Mon/Wed/Fri 9:00–9:50 AM + Tue Lab 3:00–5:00 PM", DepartmentId = 4, DepartmentName = "Physics", InstructorId = 4 },
            new() { Id = 12, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, cultures, and events from antiquity through the late medieval period. Explores political, economic, and social developments.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", DepartmentId = 5, DepartmentName = "History", InstructorId = 6 },
            new() { Id = 13, Code = "HIST 202", Title = "Modern World History", Description = "From the Enlightenment to the present. Examines revolutions, industrialization, imperialism, world wars, and globalization.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", DepartmentId = 5, DepartmentName = "History", InstructorId = 6, IsFeatured = true },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null, int? credits = null)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (credits.HasValue && credits.Value > 0)
        {
            query = query.Where(c => c.Credits == credits.Value);
        }

        return query.OrderBy(c => c.Code).ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);

    public bool SubmitEnrollment(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return GetCourse(request.CourseId) is not null;
    }
}

