+            new() { Id = 6, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations. Essential for computer science, physics, and engineering students.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", DepartmentId = 2, DepartmentName = "Mathematics", InstructorId = 3, IsFeatured = true },
+            new() { Id = 7, Code = "MATH 301", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis. Applications to data science and research.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 2, DepartmentName = "Mathematics", InstructorId = 3 },
+            new() { Id = 8, Code = "ENG 101", Title = "College Composition", Description = "Develop critical reading, analytical thinking, and academic writing skills. Emphasis on thesis-driven essays, research methods, and proper citation.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 3, DepartmentName = "English", InstructorId = 5 },
+            new() { Id = 9, Code = "ENG 220", Title = "American Literature", Description = "Survey of American literary works from the colonial era to the present. Explores themes of identity, democracy, and social change through major authors.", Credits = 3, Schedule = "Tue/Thu 2:00–3:15 PM", DepartmentId = 3, DepartmentName = "English", InstructorId = 5, IsFeatured = true },
+            new() { Id = 10, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with weekly lab sessions. Co-requisite: MATH 101.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM + Thu Lab 3:00–5:00 PM", DepartmentId = 4, DepartmentName = "Physics", InstructorId = 4 },
+            new() { Id = 11, Code = "PHYS 201", Title = "General Physics II", Description = "Electricity, magnetism, optics, and modern physics. Continuation of PHYS 101 with lab component.", Credits = 4, Schedule = "Mon/Wed/Fri 9:00–9:50 AM + Tue Lab 3:00–5:00 PM", DepartmentId = 4, DepartmentName = "Physics", InstructorId = 4 },
+            new() { Id = 12, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, cultures, and events from antiquity through the late medieval period. Explores political, economic, and social developments.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", DepartmentId = 5, DepartmentName = "History", InstructorId = 6 },
+            new() { Id = 13, Code = "HIST 202", Title = "Modern World History", Description = "From the Enlightenment to the present. Examines revolutions, industrialization, imperialism, world wars, and globalization.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", DepartmentId = 5, DepartmentName = "History", InstructorId = 6, IsFeatured = true },
+        };
+    }
+
+    public List<Department> GetDepartments() => _departments;
+
+    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);
+
+    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null, int? credits = null)
+    {
+        var query = _courses.AsEnumerable();
+
+        if (!string.IsNullOrWhiteSpace(searchTerm))
+        {
+            var term = searchTerm.Trim();
+            query = query.Where(c =>
+                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
+                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
+                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
+        }
+
+        if (departmentId.HasValue && departmentId.Value > 0)
+        {
+            query = query.Where(c => c.DepartmentId == departmentId.Value);
+        }
+
+        if (credits.HasValue && credits.Value > 0)
+        {
+            query = query.Where(c => c.Credits == credits.Value);
+        }
+
+        return query.OrderBy(c => c.Code).ToList();
+    }
+
+    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);
+
+    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
+
+    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);
+
+    public bool SubmitEnrollment(EnrollmentRequest request)
+    {
+        // In a real app, this would persist to a database
+        return GetCourse(request.CourseId) is not null;
+    }
+}
