    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search courses…"
               @bind="SearchTerm" @bind:event="oninput" @bind:after="OnFilterChanged" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="SelectedDepartmentId" @bind:after="OnFilterChanged">
            <option value="0">All Departments</option>
            @foreach (var dept in Departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="SelectedCredits" @bind:after="OnFilterChanged">
            <option value="0">Any Credits</option>
            <option value="3">3 Credits</option>
            <option value="4">4 Credits</option>
        </select>
    </div>
</div>

