    [Parameter] public int SelectedCredits { get; set; }
    [Parameter] public EventCallback<(string Search, int DeptId, int Credits)> OnFiltersChanged { get; set; }

    private async Task OnFilterChanged()
    {
        await OnFiltersChanged.InvokeAsync((SearchTerm, SelectedDepartmentId, SelectedCredits));
    }
}
