arguments.file_text:
@page "/courses"
@rendermode InteractiveServer
@inject ICatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Browse Courses — University Catalog</PageTitle>

<h1 class="mb-4">Browse Courses</h1>

<CourseFilters Departments="departments"
              SearchTerm="@searchTerm"
              SelectedDepartmentId="@selectedDeptId"
              SelectedCredits="@selectedCredits"
              OnFiltersChanged="HandleFiltersChanged" />

<p class="text-muted mb-3">Showing @courses.Count course(s)</p>

<CourseList Courses="courses" />

@code {
    private List<Department> departments = new();
    private List<Course> courses = new();
    private string searchTerm = string.Empty;
    private int selectedDeptId;
    private int selectedCredits;

    [SupplyParameterFromQuery(Name = "dept")]
    private int? DeptFromQuery { get; set; }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();

        if (DeptFromQuery.HasValue)
        {
            selectedDeptId = DeptFromQuery.Value;
        }

        LoadCourses();
    }

    private void HandleFiltersChanged((string Search, int DeptId, int Credits) filters)
    {
        searchTerm = filters.Search;
        selectedDeptId = filters.DeptId;
        selectedCredits = filters.Credits;
        LoadCourses();
    }

    private void LoadCourses()
    {
        courses = CatalogService.GetCourses(
            string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm,
            selectedDeptId > 0 ? selectedDeptId : null,
            selectedCredits > 0 ? selectedCredits : null);
    }
}

@page "/courses/{Id:int}"
@inject ICatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found") — University Catalog</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">
        <h4>Course Not Found</h4>
        <p>The requested course could not be found. <a href="courses">Browse all courses</a>.</p>
    </div>
}
else
{
    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
