@page "/enroll"
@inject ICatalogService CatalogService

<PageTitle>Enroll — University Catalog</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Enrollment Request Submitted!</h4>
        <p>Thank you, <strong>@Model!.StudentName</strong>. Your enrollment request for
            <strong>@courses.FirstOrDefault(c => c.Id == Model.CourseId)?.Title</strong> has been received.</p>
        <a href="courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-lg-8">
            <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment" Enhance>
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="Model!.StudentName" />
                    <ValidationMessage For="() => Model!.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model!.StudentId" />
                    <ValidationMessage For="() => Model!.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="Model!.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model!.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
        <div class="col-lg-4">
            <div class="card bg-light">
                <div class="card-body">
                    <h5 class="card-title">Need help?</h5>
                    <p class="card-text">Browse the <a href="courses">course catalog</a> to find the right course before enrolling.</p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private List<Course> courses = new();
    private bool submitted;

    [SupplyParameterFromForm]
    private EnrollmentRequest? Model { get; set; }

    [SupplyParameterFromQuery(Name = "courseId")]
    private int? PreselectedCourseId { get; set; }

    protected override void OnInitialized()
    {
        Model ??= new();
        courses = CatalogService.GetCourses();

        if (PreselectedCourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = PreselectedCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        submitted = CatalogService.SubmitEnrollment(Model!);
    }
}

